                merchant: params.merchant,
                payer: msg.sender,
                token: token,
                amount: amount
            });

        (address adjustedToken, uint256 adjustedAmount) = _hookManager
            .adjustTokenAmount(adjustTokenAmountParams);

        Params.RouteTransaction memory routeParams = Params.RouteTransaction({
