            payer: msg.sender,
            token: token,
            amount: amount,
            adjustedToken: adjustedToken,
            adjustedAmount: adjustedAmount
        });

        _hookManager.afterPayment(afterPaymentParams);

        emit RecurrentTransactionCreated(
            transactionId,
            msg.sender,
            params.merchant,
            params.subscriptionId,
            dueDate,
            token,
            amount,
            adjustedToken,
            adjustedAmount,
